#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = (1<<20)+5;
int n,m,a[N],dis[N];
queue<int> q;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}

int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)a[i]=read();
    for(int i=0;i<(1<<m);i++)dis[i]=-1;
    for(int i=1;i<=n;i++)
        dis[a[i]]=0,q.push(a[i]);
    while(!q.empty()){
        int u=q.front();q.pop();
        for(int i=0;i<m;i++){
            int v=u^(1<<i);
            if(dis[v]==-1)dis[v]=dis[u]+1,q.push(v);
        }
    }for(int i=1;i<=n;i++)
        cout<<m-dis[((1<<m)-1)^a[i]]<<" ";
    return 0;
}
